import { motion } from 'framer-motion';
import { FiUpload, FiArrowRight, FiPlay } from 'react-icons/fi';
import { Player } from '@lottiefiles/react-lottie-player';

const Hero = () => {
  return (
    <section className="relative overflow-hidden bg-gradient-to-br from-gray-900 to-purple-900 py-24 md:py-32">
      {/* Animated particles background */}
      <div className="absolute inset-0 opacity-20">
        {[...Array(30)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute rounded-full bg-purple-500"
            style={{
              width: `${Math.random() * 8 + 2}px`,
              height: `${Math.random() * 8 + 2}px`,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              x: [0, (Math.random() - 0.5) * 50],
              y: [0, (Math.random() - 0.5) * 50],
              opacity: [0.1, 0.8, 0.1],
            }}
            transition={{
              duration: 10 + Math.random() * 20,
              repeat: Infinity,
            }}
          />
        ))}
      </div>

      <div className="relative max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 grid lg:grid-cols-2 gap-12 items-center">
        {/* Text Content */}
        <div className="text-center lg:text-left">
          {/* Headline */}
          <motion.h1
            className="text-4xl md:text-5xl lg:text-6xl font-bold text-white mb-6 leading-tight"
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <span className="block">Detect Deepfakes Instantly</span>
            <span className="bg-gradient-to-r from-purple-400 to-cyan-300 bg-clip-text text-transparent">
              with AI-Powered Accuracy
            </span>
          </motion.h1>

          {/* Subheadline */}
          <motion.p
            className="text-lg md:text-xl text-gray-300 mb-10 max-w-lg mx-auto lg:mx-0"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.4, duration: 0.6 }}
          >
            Upload an image and let our system tell you whether it's real or fake — in seconds.
          </motion.p>

          {/* CTA Buttons */}
          <motion.div 
            className="flex flex-col sm:flex-row gap-4 justify-center lg:justify-start"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ delay: 0.8 }}
          >
            <motion.a
              href="#upload-section"
              className="flex items-center justify-center gap-2 bg-gradient-to-r from-purple-600 to-blue-500 text-white px-6 py-3 rounded-lg font-medium shadow-lg hover:shadow-xl transition-all group"
              whileHover={{ scale: 1.05 }}
              whileTap={{ scale: 0.98 }}
            >
              <FiUpload className="group-hover:animate-bounce" />
              Try It Now
              <FiArrowRight className="ml-1 group-hover:translate-x-1 transition-transform" />
            </motion.a>

            <motion.a
              href="#how-it-works"
              className="flex items-center justify-center gap-2 text-white px-6 py-3 rounded-lg font-medium border border-white/20 hover:bg-white/10 transition-colors group"
              whileHover={{ y: -2 }}
            >
              <FiPlay className="text-purple-400 group-hover:text-purple-300" />
              Learn How It Works
            </motion.a>
          </motion.div>
        </div>

        {/* AI Visualization */}
<div className="relative h-80 md:h-96 lg:h-full">
  <div className="absolute inset-0 rounded-2xl overflow-hidden bg-gradient-to-br from-purple-900/20 to-blue-900/10 flex items-center justify-center">
    
    {/* Abstract AI Core */}
    <div className="relative w-64 h-64">
      {/* Orbiting neural nodes */}
      {[...Array(6)].map((_, i) => (
        <motion.div
          key={i}
          className="absolute top-0 left-1/2 h-full w-1 origin-bottom"
          style={{
            rotate: i * 60
          }}
          animate={{
            rotate: 360
          }}
          transition={{
            duration: 12,
            repeat: Infinity,
            ease: "linear"
          }}
        >
          <div className="relative h-8 w-8 -translate-x-1/2">
            <motion.div
              className="h-full w-full rounded-full bg-gradient-to-br from-purple-400 to-blue-300 shadow-lg"
              animate={{
                scale: [1, 1.2, 1],
                opacity: [0.8, 1, 0.8]
              }}
              transition={{
                duration: 3,
                repeat: Infinity,
                delay: i * 0.3
              }}
            />
          </div>
        </motion.div>
      ))}

      {/* Central AI processor */}
      <div className="absolute inset-0 flex items-center justify-center">
        <motion.div 
          className="h-20 w-20 rounded-full bg-gradient-to-br from-purple-500 to-blue-400 flex items-center justify-center shadow-inner"
          animate={{
            scale: [1, 1.05, 1],
            rotate: [0, 5, 0]
          }}
          transition={{
            duration: 8,
            repeat: Infinity,
            repeatType: "mirror"
          }}
        >
          <svg className="h-10 w-10 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9.663 17h4.673M12 3v1m6.364 1.636l-.707.707M21 12h-1M4 12H3m3.343-5.657l-.707-.707m2.828 9.9a5 5 0 117.072 0l-.548.547A3.374 3.374 0 0014 18.469V19a2 2 0 11-4 0v-.531c0-.895-.356-1.754-.988-2.386l-.548-.547z" />
          </svg>
        </motion.div>
      </div>

      {/* Pulsing connections */}
      {[...Array(3)].map((_, i) => (
        <motion.div
          key={`connection-${i}`}
          className="absolute inset-0 rounded-full border border-white/10"
          style={{
            width: `${100 - i * 20}%`,
            height: `${100 - i * 20}%`,
            top: `${i * 10}%`,
            left: `${i * 10}%`,
          }}
          animate={{
            opacity: [0.3, 0.6, 0.3]
          }}
          transition={{
            duration: 4 + i,
            repeat: Infinity,
            delay: i * 0.5
          }}
        />
      ))}
    </div>
  </div>
</div>
      </div>
    </section>
  );
};

export default Hero;
